// Define the verifyToken middleware function
def verify_token(req, res, next):
    # Check the token for validity
    if req.headers.get('Authorization') != 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4gRG9lIiwiaWF0IjoxNTE2MjM5MDIyfQ.SflKxwRJSMeKKF2QT4fwpMeJf36POk6yJV_adQssw5c':
        return res.status(401).send({'error': 'Invalid token'})
    next()

# Define the route handler
def route_handler(req, res):
    # Return the request data
    res.send(req.body)

# Export the route handler
from flask import Flask, request
app = Flask(__name__)
app.before_request(verify_token)
app.add_url_rule('/', view_func=route_handler, methods=['POST'])

